css:
body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  background: var(--gradient-secondary);
  background-attachment: fixed;
  color: #3A3350;
  -webkit-text-size-adjust: 100%;
  min-height: 100vh;
}

button {
  font-family: inherit;
  cursor: pointer;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  overflow: hidden;
}
button:before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 0;
  height: 0;
  background: rgba(255, 255, 255, 0.3);
  border-radius: 50%;
  transform: translate(-50%, -50%);
  transition: width 0.6s, height 0.6s;
}
button:active:before {
  width: 300px;
  height: 300px;
}

input, textarea, select {
  font-family: inherit;
  font-size: 16px;
  border: 2px solid rgba(203, 192, 211, 0.6);
  border-radius: var(--border-radius-xl);
  padding: var(--spacing-lg) var(--spacing-xl);
  color: #3A3350;
  width: 100%;
  background: rgba(255, 255, 255, 0.9);
  backdrop-filter: blur(10px);
  outline: none;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  box-shadow: var(--shadow-soft);
}
input:focus, textarea:focus {
  border-color: #9000FF;
  background: rgba(255, 255, 255, 0.95);
  box-shadow: var(--shadow-glow), var(--shadow-medium);
  transform: translateY(-1px);
}

::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: rgba(203, 192, 211, 0.1); border-radius: 3px; }
::-webkit-scrollbar-thumb { background: rgba(144, 0, 255, 0.3); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: rgba(144, 0, 255, 0.5); }

@keyframes slideUp {
  from { transform: translateY(60px); opacity: 0; }
  to { transform: translateY(0); opacity: 1; }
}
@keyframes momentPop {
  0% { transform: scale(0.4) rotate(-8deg); opacity: 0; }
  70% { transform: scale(1.1) rotate(2deg); }
  100% { transform: scale(1) rotate(0); opacity: 1; }
}
@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}
@keyframes bounceIn {
  0% { transform: scale(0.3); opacity: 0; }
  50% { transform: scale(1.05); }
  70% { transform: scale(0.9); }
  100% { transform: scale(1); opacity: 1; }
}

.glass {
  background: var(--gradient-glass);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.2);
}
.shimmer {
  background: linear-gradient(90deg, #f0edf8 25%, #e8e4f4 50%, #f0edf8 75%);
  background-size: 600px 100%;
  animation: shimmer 1.4s infinite linear;
}
